javascript: document.addEventListener('DOMContentLoaded', function() {
const toggleButton = document.getElementById('toggle-button');
const sidebar = document.getElementById('sidebar');

toggleButton.addEventListener('click', function() {
    sidebar.classList.toggle('animate-slide-out');
});

sidebar.addEventListener('click', function(e) {
    if (e.target.classList.contains('sidebar-link')) {
        sidebar.classList.remove('animate-slide-in');
        sidebar.classList.add('animate-slide-out');
    }
});

const sidebarLinks = document.querySelectorAll('#sidebar .sidebar-link');
sidebarLinks.forEach(function(link) {
    link.addEventListener('click', function() {
        sidebar.classList.remove('animate-slide-in');
        sidebar.classList.add('animate-slide-out');
    });
});
});

/*
 * Define animations for sliding the sidebar
 */

@keyframes slide-in {
    0% {
        transform: translateX(-100%);
    }
    100% {
        transform: translateX(0);
    }
}

@keyframes slide-out {
    0% {
        transform: translateX(0);
    }
    100% {
        transform: translateX(-100%);
    }
}

.sidebar {
    animation: 0.5s ease-out 0s 1 slide-in;
}

.sidebar.animate-slide-out {
    animation: 0.5s ease-out 0s 1 slide-out;
}

css: .sidebar {
    position: absolute;
    top: 0;
    left: -200px;
    height: 100vh;
    width: 200px;
    background-color: #337ab7;
    color: #fff;
    text-align: center;
    padding: 20px;
    transition: all 0.5s ease-out;
}

.sidebar.animate-slide-in {
    animation: slide-in 0.5s ease-out 0s 1;
}

.sidebar.animate-slide-out {
    animation: slide-out 0.5s ease-out 0s 1;
}

.sidebar-link {
    display: block;
    padding: 10px 20px;
    cursor: pointer;
}

.sidebar-link:hover {
    background-color: #337ab7;
    color: #fff;
}

